UPDATE clients
SET document_id = '13829413904',
    name = 'BCB Padaria Central',
    balance = 20.00,
    monthly_used = 0.00,
    updated_at = CURRENT_TIMESTAMP
WHERE id = '11111111-1111-1111-1111-111111111111';

DELETE FROM financial_transactions financial_transaction
USING messages message
JOIN conversations conversation ON conversation.id = message.conversation_id
WHERE financial_transaction.message_id = message.id
  AND conversation.client_id = '11111111-1111-1111-1111-111111111111';

DELETE FROM messages message
USING conversations conversation
WHERE message.conversation_id = conversation.id
  AND conversation.client_id = '11111111-1111-1111-1111-111111111111';

DELETE FROM conversations
WHERE client_id = '11111111-1111-1111-1111-111111111111';

